6. [TestClass]
7. public sealed class DiscountCalculatorTests
8. {
9.     // -- CalculateDiscount tests --
10.     // These tests exercise the middle of each tier but never test the exact boundaries.
11.     // A mutation like >= 1000 → > 1000 would survive.
12. 
13.     [TestMethod]
14.     public void CalculateDiscount_LargeOrder_Returns15Percent()
15.     {
16.         var calc = new DiscountCalculator();
17.         var discount = calc.CalculateDiscount(2000m);
18.         Assert.AreEqual(300m, discount);
19.     }
20. 
21.     [TestMethod]
22.     public void CalculateDiscount_MediumOrder_Returns10Percent()
23.     {
24.         var calc = new DiscountCalculator();
25.         var discount = calc.CalculateDiscount(750m);
26.         Assert.AreEqual(75m, discount);
27.     }
28. 
29.     [TestMethod]
30.     public void CalculateDiscount_SmallOrder_Returns5Percent()
31.     {
32.         var calc = new DiscountCalculator();
33.         var discount = calc.CalculateDiscount(200m);
34.         Assert.AreEqual(10m, discount);
35.     }
36. 
37.     [TestMethod]
38.     public void CalculateDiscount_TinyOrder_ReturnsZero()
39.     {
40.         var calc = new DiscountCalculator();
