57. 
58.     [TestMethod]
59.     public void CalculateShipping_LargeOrder_FreeShipping()
60.     {
61.         var calc = new DiscountCalculator();
62.         var cost = calc.CalculateShipping(500m, 2.0, false);
63.         Assert.AreEqual(0m, cost);
