67.     public void CalculateShipping_SmallOrder_ReturnsBaseCost()
68.     {
69.         var calc = new DiscountCalculator();
70.         var cost = calc.CalculateShipping(50m, 2.0, false);
71.         Assert.AreEqual(6.00m, cost);
72.     }
73. 
74.     [TestMethod]
75.     public void CalculateShipping_ZeroWeight_Throws()
76.     {
77.         var calc = new DiscountCalculator();
