    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        var calc = new DiscountCalculator();
        Assert.AreEqual(90m, calc.ApplyCoupon(100m, "save10"));
    }

    [TestMethod]
    public void ApplyCoupon_FloorAt1_WhenDiscountExceedsTotal()
    {
        var calc = new DiscountCalculator();
        // FLAT50 on a $2 order: 2 - 50 = -48, clamped to 1.00
        Assert.AreEqual(1.00m, calc.ApplyCoupon(2m, "FLAT50"));
    }

    [TestMethod]
    public void ApplyCoupon_FloorAt1_ExactlyAtFloor()
    {
        var calc = new DiscountCalculator();
        // FLAT5 on $6 order: 6 - 5 = 1.00, exactly at floor
        Assert.AreEqual(1.00m, calc.ApplyCoupon(6m, "FLAT5"));
    }

    [TestMethod]
    public void ApplyCoupon_JustAboveFloor()
    {
        var calc = new DiscountCalculator();
        // FLAT5 on $7 order: 7 - 5 = 2.00, above floor
        Assert.AreEqual(2.00m, calc.ApplyCoupon(7m, "FLAT5"));
    }

